"""
Code emitters for OaTypeAutogen.
Generates C++ header and implementation files from type schemas.
"""
from oatypeautogen_lib.schema import EnumDef, StructDef, TypeSchema


GEN_HEADER = (
	"// AUTO-GENERATED by Tools/TypeAutogen/oatypeautogen.py — DO NOT EDIT.\n"
	"// Source of truth: Tools/TypeAutogen/Schema/{schema_name}.\n"
	"// Regenerate via: python3 Tools/TypeAutogen/oatypeautogen.py --live\n"
)


def emit_enum_header(enum_def: EnumDef, namespace: str) -> str:
	"""Emit enum class declaration for header."""
	lines = [f"enum class {enum_def.name} : {enum_def.underlying_type} {{"]
	
	for val in enum_def.values:
		if val.comment:
			lines.append(f"\t{val.name} = {val.value if val.value is not None else ''},  // {val.comment}")
		else:
			if val.value is not None:
				lines.append(f"\t{val.name} = {val.value},")
			else:
				lines.append(f"\t{val.name},")
	
	lines.append("};")
	
	# ToString declaration
	if enum_def.generate_tostring:
		lines.append(f"[[nodiscard]] constexpr const char* {enum_def.name}ToString({enum_def.name} InType) noexcept;")
	
	# FromString declaration
	if enum_def.generate_fromstring:
		lines.append(f"[[nodiscard]] {enum_def.name} {enum_def.name}FromString(const char* InStr) noexcept;")
	
	lines.append("")
	return "\n".join(lines)


def emit_enum_tostring(enum_def: EnumDef) -> str:
	"""Emit ToString implementation for enum."""
	lines = [f"constexpr const char* {enum_def.name}ToString({enum_def.name} InType) noexcept {{"]
	lines.append("\tswitch (InType) {")
	
	for val in enum_def.values:
		lines.append(f"\t\tcase {enum_def.name}::{val.name}: return \"{val.name}\";")
	
	lines.append("\t\tdefault: return \"unknown\";")
	lines.append("\t}")
	lines.append("}")
	lines.append("")
	return "\n".join(lines)


def emit_enum_fromstring(enum_def: EnumDef) -> str:
	"""Emit FromString implementation for enum (non-constexpr for strcmp)."""
	lines = [f"{enum_def.name} {enum_def.name}FromString(const char* InStr) noexcept {{"]
	lines.append("\t// Simple string comparison (could be optimized with hash)")
	
	for val in enum_def.values:
		lines.append(f"\tif (strcmp(InStr, \"{val.name}\") == 0) return {enum_def.name}::{val.name};")
	
	lines.append(f"\treturn {enum_def.name}::{enum_def.values[0].name};  // Default to first value")
	lines.append("}")
	lines.append("")
	return "\n".join(lines)


def emit_struct_header(struct_def: StructDef, namespace: str) -> str:
	"""Emit struct declaration for header."""
	lines = [f"struct {struct_def.name} {{"]
	
	for field in struct_def.fields:
		if field.comment:
			lines.append(f"\t{field.type} {field.name};  // {field.comment}")
		else:
			if field.default:
				lines.append(f"\t{field.type} {field.name} = {field.default};")
			else:
				lines.append(f"\t{field.type} {field.name};")
	
	# Serialization declaration (inside struct)
	if struct_def.generate_serialize:
		lines.append(f"\tbool SerializeToYaml(const char* InPath) const;")
		lines.append(f"\tbool LoadFromYaml(const char* InPath);")
	
	# Validation declaration (inside struct)
	if struct_def.generate_validate:
		lines.append(f"\tbool Validate() const;")
	
	lines.append("};")
	lines.append("")
	return "\n".join(lines)


def emit_header_file(schema: TypeSchema, schema_name: str) -> str:
	"""Emit complete header file."""
	lines = [GEN_HEADER.format(schema_name=schema_name)]
	lines.append(f"#pragma once")
	lines.append("")
	lines.append(f"#include <Oa/Core/Types.h>")
	lines.append("")
	
	for enum in schema.enums:
		lines.append(emit_enum_header(enum, schema.namespace))
	
	for struct in schema.structs:
		lines.append(emit_struct_header(struct, schema.namespace))
	
	return "\n".join(lines)


def emit_struct_serialize(struct_def: StructDef) -> str:
	"""Emit YAML serialization implementation for struct."""
	lines = [f"bool {struct_def.name}::SerializeToYaml(const char* InPath) const {{"]
	lines.append("\t// TODO: Implement YAML serialization using yaml-cpp")
	lines.append("\t// For now, return false (not implemented)")
	lines.append("\t(void)InPath;")
	lines.append("\treturn false;")
	lines.append("}")
	lines.append("")
	return "\n".join(lines)


def emit_struct_load(struct_def: StructDef) -> str:
	"""Emit YAML load implementation for struct."""
	lines = [f"bool {struct_def.name}::LoadFromYaml(const char* InPath) {{"]
	lines.append("\t// TODO: Implement YAML loading using yaml-cpp")
	lines.append("\t// For now, return false (not implemented)")
	lines.append("\t(void)InPath;")
	lines.append("\treturn false;")
	lines.append("}")
	lines.append("")
	return "\n".join(lines)


def emit_struct_validate(struct_def: StructDef) -> str:
	"""Emit validation implementation for struct."""
	lines = [f"bool {struct_def.name}::Validate() const {{"]
	lines.append("\t// Basic validation: check for reasonable values")
	lines.append("\t// TODO: Add field-specific validation")
	
	for field in struct_def.fields:
		if "Width" in field.name or "Height" in field.name:
			lines.append(f"\tif ({field.name} == 0) return false;")
		elif "Count" in field.name or "Size" in field.name:
			lines.append(f"\tif ({field.name} == 0) return false;")
	
	lines.append("\treturn true;")
	lines.append("}")
	lines.append("")
	return "\n".join(lines)


def emit_cpp_file(schema: TypeSchema, schema_name: str) -> str:
	"""Emit complete implementation file."""
	lines = [GEN_HEADER.format(schema_name=schema_name)]
	
	# Include the generated header
	domain = schema.domain
	header_path = f"<Oa/{domain}/Type.gen.h>" if domain != "Core" else "<Oa/Core/Type.gen.h>"
	lines.append(f"#include {header_path}")
	lines.append("")
	
	# Include cstring for strcmp if any FromString is generated
	has_fromstring = any(enum.generate_fromstring for enum in schema.enums)
	if has_fromstring:
		lines.append(f"#include <cstring>")
		lines.append("")
	
	# Include yaml-cpp if any serialization is generated
	has_serialize = any(struct.generate_serialize for struct in schema.structs)
	if has_serialize:
		lines.append(f"#include <Oa/Core/Yaml.h>")
		lines.append("")
	
	for enum in schema.enums:
		if enum.generate_tostring:
			lines.append(emit_enum_tostring(enum))
		if enum.generate_fromstring:
			lines.append(emit_enum_fromstring(enum))
	
	for struct in schema.structs:
		if struct.generate_serialize:
			lines.append(emit_struct_serialize(struct))
			lines.append(emit_struct_load(struct))
		if struct.generate_validate:
			lines.append(emit_struct_validate(struct))
	
	return "\n".join(lines)
